              { word: 'כָּתוּב', transliteration: 'Katub', translation: 'Escrito', audioLang: 'he-IL' },
              { word: 'שֹׁמֵר', transliteration: 'Shomer', translation: 'Guardando / Guarda', audioLang: 'he-IL' },
              { word: 'בָּרוּךְ', transliteration: 'Baruk', translation: 'Bendito / Abençoado', audioLang: 'he-IL' }
